import{_ as t,o as n,c as i,a0 as a}from"./chunks/framework.BJ65gTIr.js";const u=JSON.parse('{"title":"Architecture Overview","description":"Harness-First Engineering — where the model provides intelligence and the harness provides reliability","frontmatter":{"title":"Architecture Overview","description":"Harness-First Engineering — where the model provides intelligence and the harness provides reliability"},"headers":[],"relativePath":"architecture/overview.md","filePath":"architecture/overview.md","lastUpdated":1775364101000}'),s={name:"architecture/overview.md"};function r(o,e,l,d,c,h){return n(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><h2 id="the-defining-principle" tabindex="-1">The Defining Principle <a class="header-anchor" href="#the-defining-principle" aria-label="Permalink to &quot;The Defining Principle&quot;">​</a></h2><p><strong>Harness-First Engineering</strong> — the harness isn&#39;t an afterthought; it&#39;s the foundation.</p><p>In the rapidly evolving landscape of AI-assisted software engineering, the distinction between what the model knows and what the system guarantees has become the defining architectural question. This project embraces a fundamental principle: <strong>the model provides intelligence, the harness provides reliability</strong>.</p><p>This is not merely a division of labor — it is an architectural constraint that shapes every design decision, from the permission system that guards dangerous operations to the context management that maximizes the utility of limited context windows.</p><h2 id="five-architectural-advantages" tabindex="-1">Five Architectural Advantages <a class="header-anchor" href="#five-architectural-advantages" aria-label="Permalink to &quot;Five Architectural Advantages&quot;">​</a></h2><h3 id="a-harness-first-engineering" tabindex="-1">a. Harness-First Engineering <a class="header-anchor" href="#a-harness-first-engineering" aria-label="Permalink to &quot;a. Harness-First Engineering&quot;">​</a></h3><p>When building an AI agent system that operates with the same privileges as its user, reliability cannot be layered on top — it must be embedded from the first line of code.</p><p><strong>Permission control</strong>, <strong>timeout protection</strong>, <strong>output truncation</strong>, and <strong>session persistence</strong> aren&#39;t features — they&#39;re the safety net that makes AI agents production-ready. The model can hallucinate, misinterpret instructions, or choose the wrong tool. But the harness must never permit a destructive operation without authorization, must never hang indefinitely, and must never lose the user&#39;s work.</p><table tabindex="0"><thead><tr><th>Property</th><th>Guarantee</th></tr></thead><tbody><tr><td>Permission Control</td><td>No destructive operation executes without user consent or policy approval</td></tr><tr><td>Timeout Protection</td><td>Misbehaving tools (runaway grep, infinite loop) cannot hang the session</td></tr><tr><td>Output Truncation</td><td>Single tool response cannot consume the entire context window</td></tr><tr><td>Session Persistence</td><td>Agent resumes after interruption without losing conversation history</td></tr></tbody></table><h3 id="b-context-window-as-scarce-resource" tabindex="-1">b. Context Window as Scarce Resource <a class="header-anchor" href="#b-context-window-as-scarce-resource" aria-label="Permalink to &quot;b. Context Window as Scarce Resource&quot;">​</a></h3><p>Modern LLMs offer generous context windows, but &quot;generous&quot; is a relative term when representing an entire codebase, multiple files, and ongoing conversation history. This architecture treats context as a scarce resource to be managed, not a luxury to be spent freely.</p><ul><li><strong>Lazy Tool Loading</strong>: Tools are registered in a central registry; only tool definitions (name, description, input schema) are sent to the model — not their implementations</li><li><strong>250-Character Skill Descriptions</strong>: Force discipline in how capabilities are communicated to the model</li><li><strong>Three-Tier Compaction</strong>: Messages retained in full until threshold, then compressed into summaries that preserve key information while reducing token count</li></ul><h3 id="c-layered-permission-defense" tabindex="-1">c. Layered Permission Defense <a class="header-anchor" href="#c-layered-permission-defense" aria-label="Permalink to &quot;c. Layered Permission Defense&quot;">​</a></h3><p>Trust is not binary, and neither is authorization. This system implements a three-tier permission model that reflects real-world security thinking:</p><table tabindex="0"><thead><tr><th>Level</th><th>Capability</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>ReadOnly</strong></td><td>File reading, globbing, grep searching</td><td>Safe exploration of codebases</td></tr><tr><td><strong>WorkspaceWrite</strong></td><td>File creation, modification, editing</td><td>Controlled development work</td></tr><tr><td><strong>DangerFullAccess</strong></td><td>Shell execution, deletions, network operations</td><td>Full automation with explicit approval</td></tr></tbody></table><p>The permission system doesn&#39;t merely check a level — it evaluates each operation against <strong>glob rule matching</strong> to determine whether specific paths or operations are permitted. A policy might allow editing files in <code>/src/</code> while blocking modifications to <code>/config/</code> or <code>/tests/</code>.</p><p><strong>Session memory</strong> means the system remembers approval decisions within a session, preventing repetitive prompts for the same operation. A <strong>human-in-the-loop approval</strong> mode exists for operations requiring explicit confirmation before execution — critical for destructive operations or shell commands that could compromise the system.</p><h3 id="d-local-first-execution" tabindex="-1">d. Local-First Execution <a class="header-anchor" href="#d-local-first-execution" aria-label="Permalink to &quot;d. Local-First Execution&quot;">​</a></h3><p>This system runs as a pure Go binary with zero runtime dependencies. There is no Python environment to configure, no Node.js runtime to maintain, no virtual machine to manage. The agent executes in the full environment of the host machine, with access to all system resources, environment variables, and installed tooling.</p><p>This <strong>local-first</strong> approach eliminates virtualization overhead and provides maximum performance. The agent can invoke the same build tools, linters, and test runners that developers use daily. There is no abstraction layer between the model&#39;s intent and the system&#39;s actual capabilities.</p><h3 id="e-mcp-as-universal-bridge" tabindex="-1">e. MCP as Universal Bridge <a class="header-anchor" href="#e-mcp-as-universal-bridge" aria-label="Permalink to &quot;e. MCP as Universal Bridge&quot;">​</a></h3><p>The Model Context Protocol (MCP) is not a closed ecosystem — it is an interoperability hub. This system treats MCP as a bridge to external tool ecosystems, enabling the agent to discover and utilize capabilities beyond its built-in set.</p><p>MCP servers can be configured to provide specialized tooling: database access, API integrations, cloud service management, or domain-specific analyzers. The agent treats MCP tools the same as built-in tools — with full permission enforcement and the same execution guarantees.</p><h2 id="agent-loop-state-machine" tabindex="-1">Agent Loop: State Machine <a class="header-anchor" href="#agent-loop-state-machine" aria-label="Permalink to &quot;Agent Loop: State Machine&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐  tool_use  ┌──────────────┐</span></span>
<span class="line"><span>│ REQUEST  │───────────▶│ TOOL_EXEC    │</span></span>
<span class="line"><span>│          │◀───────────│              │</span></span>
<span class="line"><span>└────┬─────┘  result    └──────┬───────┘</span></span>
<span class="line"><span>     │                         │</span></span>
<span class="line"><span>end_turn│                 error│</span></span>
<span class="line"><span>     ▼                         ▼</span></span>
<span class="line"><span>┌──────────┐           ┌──────────────┐</span></span>
<span class="line"><span>│ TERMINATE│           │ CONTINUE     │</span></span>
<span class="line"><span>└──────────┘           └──────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><table tabindex="0"><thead><tr><th>State</th><th>Transition</th><th>Condition</th></tr></thead><tbody><tr><td>REQUEST</td><td>→ TOOL_EXEC</td><td>Model invokes tool (tool_use)</td></tr><tr><td>REQUEST</td><td>→ TERMINATE</td><td>Task complete (end_turn)</td></tr><tr><td>TOOL_EXEC</td><td>→ CONTINUE</td><td>Tool succeeded, continue loop</td></tr><tr><td>TOOL_EXEC</td><td>→ CONTINUE</td><td>Tool failed with recoverable error</td></tr><tr><td>TOOL_EXEC</td><td>→ TERMINATE</td><td>Non-recoverable failure</td></tr></tbody></table><h2 id="design-decisions" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Decision</th><th>Rationale</th><th>Trade-off</th></tr></thead><tbody><tr><td><strong>Go Implementation</strong></td><td>Static linking, single-binary deployment, predictable memory usage</td><td>Less flexible than interpreted languages</td></tr><tr><td><strong>Three-Tier Permission</strong></td><td>Binary allow/deny insufficient for varied development workflows</td><td>More complex configuration, enables practical use</td></tr><tr><td><strong>Glob Rule Matching</strong></td><td>Fine-grained control over which files can be modified</td><td>Requires users to understand glob patterns</td></tr><tr><td><strong>250-Character Tool Descriptions</strong></td><td>Forces discipline in capability communication; prevents context bloat</td><td>May omit useful tool details</td></tr><tr><td><strong>MAX_TURNS = 50</strong></td><td>Prevents resource exhaustion from infinite loops</td><td>Complex tasks may need more iterations</td></tr><tr><td><strong>Three-Tier Message Compaction</strong></td><td>Preserves semantic content while managing token limits</td><td>Compression is lossy; some context may be lost</td></tr><tr><td><strong>MCP as External Adapter</strong></td><td>Protocol-agnostic tool discovery; ecosystem integration</td><td>MCP servers add external dependencies</td></tr></tbody></table><h2 id="target-audience" tabindex="-1">Target Audience <a class="header-anchor" href="#target-audience" aria-label="Permalink to &quot;Target Audience&quot;">​</a></h2><p>This documentation is written for:</p><ul><li><strong>AI Agent Architecture Researchers</strong> — examining how harness design influences agent capabilities</li><li><strong>Senior Engineers</strong> evaluating Harness-First engineering patterns for production systems</li><li><strong>Tech Leads</strong> seeking reference implementations for production-grade AI tooling</li></ul><p>The emphasis throughout is on <em>why</em> rather than <em>what</em> — the code reveals implementation details, but these pages explain the reasoning behind them.</p><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="./design-philosophy.html">Design Philosophy</a> — Deep dive into the intelligence/reliability separation</li><li><a href="./agent-loop.html">Agent Loop</a> — State machine mechanics and history management</li><li><a href="./tools.html">Tool System</a> — Built-in tools and extension mechanisms</li><li><a href="./../guide/configuration.html">Configuration Guide</a> — Permission policies and model settings</li></ul>`,35)])])}const m=t(s,[["render",r]]);export{u as __pageData,m as default};
